1	/**
2	 * THING session driver — talks to a real agent session over the pod's HTTP API and gives a
3	 * scenario everything it needs to ASSERT on behaviour, not just on final text.
4	 *
5	 * Why HTTP and not the WebSocket the /chat SPA uses: the WS needs a dep and buys us nothing here.
6	 * The pod exposes the same surface over HTTP (sdk/org/libs/cli/src/server/web/agent-api.ts):
7	 *
8	 *   POST /api/sessions                      {projectId, agentSlug?, resumeSessionId?, budget?}
9	 *   POST /api/sessions/:id/message          {content}                         → 202
10	 *   GET  /api/sessions/:id/events?since=N&format=json                          → {events,lastSeq}
11	 *   GET  /api/sessions/:id/asks?format=json                                    → {asks}
12	 *   POST /api/sessions/:id/ask/:askId       {value}                            → answer a prompt
13	 *
14	 * The event stream is the full execution trace (sdk/org/libs/core/src/sandbox/trace.ts), so a
15	 * scenario can assert on the things that actually matter — which agents THING delegated to, which
16	 * consent-marked globals it called, which yields resolved, tokens burned, errors raised — instead
17	 * of grading a paragraph of prose.
18	 *
19	 * IMPORTANT (consent): the consent prompter is only wired for INTERACTIVE sessions
20	 * (session-manager.ts — `consentPrompter: args.interactive ? … : undefined`). A session created
21	 * through `POST /api/sessions` is interactive, so consent cards appear as asks here. Headless
22	 * paths (hooks, delegates, webhook dispatch) fail closed by design — that is a feature to assert,
23	 * not a bug to work around.
24	 */
25	
26	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
27	
28	export class ThingSession {
29	  /**
30	   * @param {import('./pod.mjs').Pod} pod
31	   * @param {object} opts
32	   * @param {string} [opts.projectId='user']   project to run in ('user' = the default project)
33	   * @param {string} [opts.agentSlug='thing']  THING is the default agent
34	   * @param {(descriptor:object)=>unknown} [opts.onAsk]  answer asks (consent cards, forms).
35	   *        Return `undefined` to leave the ask open (the scenario answers it manually).
36	   * @param {boolean} [opts.verbose=false]     stream a live log to stdout
37	   */
38	  constructor(pod, opts = {}) {
39	    this.pod = pod;
40	    this.projectId = opts.projectId ?? 'user';
41	    this.agentSlug = opts.agentSlug ?? 'thing';
42	    this.onAsk = opts.onAsk;
43	    this.verbose = opts.verbose ?? false;
44	    this.sessionId = null;
45	    /** every trace event seen, in order — the scenario's source of truth */
46	    this.events = [];
47	    /** asks the driver saw, with what it answered */
48	    this.asks = [];
49	    this.lastSeq = 0;
50	  }
51	
52	  log(...a) {
53	    if (this.verbose) console.log('[thing]', ...a);
54	  }
55	
56	  /** Create the session. Init is async pod-side — `send()` waits it out. */
57	  async start({ resumeSessionId, budget } = {}) {
58	    const body = {
59	      projectId: this.projectId,
60	      agentSlug: this.agentSlug,
61	      ...(resumeSessionId ? { resumeSessionId } : {}),
62	      ...(budget ? { budget } : {}),
63	    };
64	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
65	    this.sessionId = sessionId;
66	    this.log('session', sessionId);
67	    return sessionId;
68	  }
69	
70	  /** Resume an existing session id (post-restart auto-resume scenario). */
71	  async resume(sessionId) {
72	    return this.start({ resumeSessionId: sessionId });
73	  }
74	
75	  /**
76	   * Pull new trace events since `lastSeq`.
77	   *
78	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
79	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
80	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
81	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
82	   * than thrown; the settle loop treats it as turn-end once work has been seen.
83	   */
84	  async pullEvents() {
85	    let res;
86	    try {
87	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
88	    } catch (err) {
89	      if (err?.status === 404) {
90	        this.sessionGone = true;
91	        return [];
92	      }
93	      throw err;
94	    }
95	    const { events, lastSeq } = res;
96	    for (const e of events ?? []) {
97	      this.events.push(e.event);
98	      if (this.verbose) this.#logEvent(e.event);
99	    }
100	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
101	    return events ?? [];
102	  }
103	
104	  #logEvent(ev) {
105	    switch (ev.type) {
106	      case 'yield':
107	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
108	        break;
109	      case 'display':
110	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
111	        break;
112	      case 'node_start':
113	        this.log(`  node_start ${ev.kind} ${ev.label}`);
114	        break;
115	      case 'node_end':
116	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
117	        break;
118	      case 'eval_error':
119	      case 'typecheck_error':
120	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
121	        break;
122	      default:
123	        break;
124	    }
125	  }
126	
127	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
128	  async openAsks() {
129	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
130	    return asks ?? [];
131	  }
132	
133	  /**
134	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
135	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
136	   * null — is a denial.
137	   */
138	  async answerAsk(askId, value) {
139	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
140	    this.log('answered ask', askId, JSON.stringify(value));
141	  }
142	
143	  /**
144	   * Send a user message and wait for the turn to settle.
145	   *
146	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
147	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
148	   * idle+quiet pair is the only reliable edge over HTTP.
149	   *
150	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
151	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
152	   * a timeout with the ask still open (which the scenario can assert on).
153	   */
154	  /**
155	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
156	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
157	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
158	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
159	   * drives self-contained follow-ups).
160	   */
161	  async #ensureAlive() {
162	    if (!this.sessionId) return;
163	    const list = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
164	    const alive = (list.sessions ?? []).some((s) => s.sessionId === this.sessionId);
165	    if (alive) return;
166	    this.log('session evicted — re-establishing');
167	    const prev = this.sessionId;
168	    try {
169	      await this.start({ resumeSessionId: prev });
170	    } catch {
171	      await this.start();
172	    }
173	    this.lastSeq = 0;
174	    this.sessionGone = false;
175	  }
176	
177	  async send(content, opts = {}) {
178	    await this.#ensureAlive();
179	    return this.#dispatchAndWait(
180	      () => this.pod.req('POST', `/api/sessions/${this.sessionId}/message`, { content }),
181	      content,
182	      opts,
183	    );
184	  }
185	
186	  /**
187	   * Send a user message WITH attachments (the file-upload path the real UI uses).
188	   *
189	   * The HTTP `POST /message` route is content-only — it silently drops attachments
190	   * (`sessions.ts` wires `sendMessage: (content) => manager.sendMessage(id, content)`, no third
191	   * arg). Only the WebSocket path carries `attachmentIds` (`ws/agent.ts` →
192	   * `msg.attachments.map(a => a.id)`). So to attach a file we open the same `/api/ws` socket the
193	   * `/chat` SPA uses, send one `{type:'sendMessage', content, attachments}` frame, then fall back to
194	   * the normal HTTP trace-poll to await the turn (the socket also streams the trace, but reusing the
195	   * HTTP settle-loop keeps one code path for "turn finished").
196	   *
197	   * @param {string} content
198	   * @param {Array<{id:string,kind:string,mediaType:string,url?:string,filename?:string}>} attachments
199	   *        AttachmentRefs from `pod.upload()`. The server trusts only `id` (re-reads bytes by id).
200	   */
201	  async sendWithAttachments(content, attachments, opts = {}) {
202	    const refs = attachments.map((a) => ({
203	      id: a.id,
204	      kind: a.kind,
205	      mediaType: a.mediaType,
206	      url: a.url ?? `/api/uploads/${a.id}`,
207	      ...(a.filename ? { filename: a.filename } : {}),
208	    }));
209	    await this.#ensureAlive();
210	    return this.#dispatchAndWait(
211	      () => this.#wsSend({ type: 'sendMessage', content, attachments: refs }),
212	      `${content}  [+${refs.length} attachment(s)]`,
213	      opts,
214	    );
215	  }
216	
217	  /** Open the pod's chat WebSocket, send one frame, resolve when it's flushed, then close. */
218	  #wsSend(frame) {
219	    const wsBase = this.pod.base.replace(/^http/, 'ws');
220	    const tokenQ = this.pod.token ? `&access_token=${encodeURIComponent(this.pod.token)}` : '';
221	    const url = `${wsBase}/api/ws?sessionId=${this.sessionId}${tokenQ}`;
222	    return new Promise((resolve, reject) => {
223	      const ws = new WebSocket(url); // Node ≥22 global WebSocket — zero-dep
224	      const fail = (e) => reject(e instanceof Error ? e : new Error(`ws error: ${JSON.stringify(e)}`));
225	      ws.addEventListener('open', () => {
226	        ws.send(JSON.stringify(frame));
227	        // Give the frame a beat to flush, then close; the turn is awaited over HTTP.
228	        setTimeout(() => {
229	          try {
230	            ws.close();
231	          } catch {
232	            /* ignore */
233	          }
234	          resolve();
235	        }, 750);
236	      });
237	      ws.addEventListener('error', fail);
238	    });
239	  }
240	
241	  async #dispatchAndWait(dispatch, logLine, { timeoutMs = 600_000, quietMs = 4_000, pollMs = 1_500 } = {}) {
242	    const startSeq = this.events.length;
243	    const t0 = Date.now();
244	    await dispatch();
245	    this.log('→', logLine.slice(0, 140));
246	
247	    let lastChange = Date.now();
248	    let sawWork = false;
249	    let quietSince = null;
250	    this.sessionGone = false;
251	
252	    while (Date.now() - t0 < timeoutMs) {
253	      const fresh = await this.pullEvents();
254	      if (fresh.length) {
255	        lastChange = Date.now();
256	        sawWork = true;
257	        quietSince = null;
258	      }
259	
260	      // If the session was evicted AFTER we saw the turn's work (a long turn's many sub-sessions
261	      // can push a small pod past `maxSessions`), the turn is effectively done — stop cleanly and
262	      // let the scenario assert on real pod state. If it vanished BEFORE any work, that's a real
263	      // failure (e.g. a mid-init pod restart), so surface it.
264	      if (this.sessionGone) {
265	        if (sawWork) return this.turn(startSeq, Date.now() - t0);
266	        throw new Error(`session ${this.sessionId} disappeared before doing any work (pod restart mid-init?)`);
267	      }
268	
269	      // Drain asks (consent cards, forms) — an unanswered ask stalls the turn forever.
270	      for (const ask of await this.openAsks().catch(() => [])) {
271	        if (this.asks.some((a) => a.id === ask.id)) continue;
272	        const answer = this.onAsk ? this.onAsk(ask.descriptor, ask) : undefined;
273	        this.asks.push({ id: ask.id, descriptor: ask.descriptor, answered: answer });
274	        if (answer !== undefined) {
275	          await this.answerAsk(ask.id, answer).catch(() => {});
276	          lastChange = Date.now();
277	        }
278	      }
279	
280	      const sessions = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
281	      const me = (sessions.sessions ?? []).find((s) => s.sessionId === this.sessionId);
282	      const idle = me?.status === 'idle';
283	      if (me?.status === 'error') {
284	        await this.pullEvents();
285	        throw new Error(`session entered error state: ${JSON.stringify(me)}`);
286	      }
287	      // Session no longer listed but we saw work → treat as completed (same eviction case).
288	      if (sawWork && !me && this.events.length > startSeq) {
289	        return this.turn(startSeq, Date.now() - t0);
290	      }
291	
292	      if (sawWork && idle && Date.now() - lastChange >= quietMs) {
293	        if (quietSince === null) quietSince = Date.now();
294	        await this.pullEvents(); // final drain
295	        return this.turn(startSeq, Date.now() - t0);
296	      }
297	      await sleep(pollMs);
298	    }
299	    await this.pullEvents();
300	    const open = await this.openAsks();
301	    throw Object.assign(
302	      new Error(
303	        `turn timed out after ${timeoutMs}ms` +
304	          (open.length ? ` with ${open.length} unanswered ask(s): ${JSON.stringify(open)}` : ''),
305	      ),
306	      { turn: this.turn(startSeq, Date.now() - t0), openAsks: open },
307	    );
308	  }
309	
310	  /** A view over just the events of one turn, with the derived facts a scenario asserts on. */
311	  turn(startSeq = 0, durationMs = 0) {
312	    const evs = this.events.slice(startSeq);
313	    return {
314	      durationMs,
315	      events: evs,
316	      text: textOf(evs),
317	      yields: evs.filter((e) => e.type === 'yield').map((e) => ({ kind: e.kind, args: e.args })),
318	      delegates: evs
319	        .filter((e) => e.type === 'yield' && e.kind === 'delegate')
320	        .map((e) => delegateRef(e.args)),
321	      errors: evs
322	        .filter((e) => e.type === 'eval_error' || e.type === 'typecheck_error')
323	        .map((e) => ({ type: e.type, message: e.message, statement: e.statement })),
324	      tokens: evs.reduce(
325	        (acc, e) =>
326	          e.type === 'llm_response'
327	            ? { in: acc.in + (e.inputTokens ?? 0), out: acc.out + (e.outputTokens ?? 0) }
328	            : acc,
329	        { in: 0, out: 0 },
330	      ),
331	      llmCalls: evs.filter((e) => e.type === 'llm_response').length,
332	      nodes: evs
333	        .filter((e) => e.type === 'node_end')
334	        .map((e) => ({ id: e.nodeId, status: e.status, ms: e.durationMs, error: e.error })),
335	    };
336	  }
337	
338	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
339	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
340	  /** Did it delegate to this `space/agent` (or just this space)? */
341	  didDelegate = (ref) =>
342	    this.events.some(
343	      (e) => e.type === 'yield' && e.kind === 'delegate' && delegateRef(e.args).startsWith(ref),
344	    );
345	  /** All consent cards raised this session. */
346	  consentCards = () => this.asks.filter((a) => a.descriptor?.type === 'ConsentCard');
347	
348	  /** Full session totals — for the performance table in the scenario report. */
349	  stats() {
350	    const t = this.turn(0, 0);
351	    return {
352	      events: this.events.length,
353	      llmCalls: t.llmCalls,
354	      tokens: t.tokens,
355	      errors: t.errors.length,
356	      delegates: t.delegates,
357	      yieldKinds: [...new Set(t.yields.map((y) => y.kind))],
358	    };
359	  }
360	}
361	
362	/** Human-readable delegate target from the yield args (`{space, agent, action}` or positional). */
363	function delegateRef(args) {
364	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
365	  if (args && typeof args === 'object') {
366	    const { space, agent, action } = args;
367	    return [space, agent, action].filter(Boolean).join('/');
368	  }
369	  return String(args);
370	}
371	
372	/** The prose THING showed the user: display() descriptors + the final assistant text. */
373	export function textOf(events) {
374	  const out = [];
375	  for (const e of events) {
376	    if (e.type === 'display') {
377	      const d = e.descriptor;
378	      const s =
379	        typeof d === 'string'
380	          ? d
381	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
382	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
383	    }
384	  }
385	  return out.join('\n');
386	}
387	
388	/** Approve every consent card; leave other asks for the scenario. */
389	export const approveAllConsent = (descriptor) =>
390	  descriptor?.type === 'ConsentCard' ? true : undefined;
391	/** Deny every consent card (for the denial branch of the consent scenario). */
392	export const denyAllConsent = (descriptor) =>
393	  descriptor?.type === 'ConsentCard' ? false : undefined;
