1	#!/usr/bin/env node
2	/**
3	 * Harness smoke test — proves the whole chain works before any scenario burns an hour on it:
4	 * register → pod → env → THING session → a real LLM turn → trace assertions.
5	 *
6	 *   node smoke.mjs [label]
7	 *
8	 * If this fails, no scenario can pass; fix the harness first.
9	 */
10	import { Pod } from './lib/pod.mjs';
11	import { ThingSession, approveAllConsent } from './lib/thing.mjs';
12	import { Report } from './lib/report.mjs';
13	import { getUser } from './provision.mjs';
14	import { budget } from './lib/gateway.mjs';
15	
16	const label = process.argv[2] ?? 'smoke';
17	const r = new Report('smoke', 'Harness smoke test');
18	
19	r.step('provision', 'a fresh prod user with a ready pod and Azure keys loaded');
20	const user = await getUser(label);
21	r.check('user registered', !!user.userId, user.userId);
22	r.check('pod reachable', !!user.pod, user.pod);
23	
24	const pod = new Pod({ base: user.pod, token: user.token });
25	
26	r.step('pod API', 'projects + store catalog answer over the Envoy-routed origin');
27	const projects = await pod.listProjects();
28	r.check('GET /api/projects', Array.isArray(projects.projects ?? projects), JSON.stringify(projects).slice(0, 200));
29	const store = await pod.storeSpaces();
30	const spaces = store.spaces ?? [];
31	r.check('store catalog non-empty', spaces.length > 0, `${spaces.length} spaces`);
32	r.note(`catalog: ${spaces.map((s) => s.id).join(', ')}`);
33	
34	r.step('THING turn', 'a real LLM turn completes and the trace shows llm calls + a display');
35	const thing = new ThingSession(pod, { verbose: true, onAsk: approveAllConsent });
36	await thing.start();
37	const turn = await thing.send('In one sentence: what can you help me build?', { timeoutMs: 240_000 });
38	r.check('turn completed', true, `${(turn.durationMs / 1000).toFixed(1)}s`);
39	r.check('LLM was called', turn.llmCalls > 0, `${turn.llmCalls} calls`);
40	r.check('THING replied', turn.text.length > 0, turn.text.slice(0, 200));
41	r.check('no eval errors', turn.errors.length === 0, JSON.stringify(turn.errors).slice(0, 300));
42	r.metric('first turn', (turn.durationMs / 1000).toFixed(1), 's');
43	r.metric('tokens', `${turn.tokens.in} in / ${turn.tokens.out} out`);
44	
45	const b = await budget(user.token).catch((e) => ({ error: String(e) }));
46	r.note(`budget: ${JSON.stringify(b)}`);
47	
48	r.save(`${new URL('.', import.meta.url).pathname}.state/smoke-report.md`);
49	process.exit(r.passed ? 0 : 1);
50

