1	/**
2	 * THING session driver — talks to a real agent session over the pod's HTTP API and gives a
3	 * scenario everything it needs to ASSERT on behaviour, not just on final text.
4	 *
5	 * Why HTTP and not the WebSocket the /chat SPA uses: the WS needs a dep and buys us nothing here.
6	 * The pod exposes the same surface over HTTP (sdk/org/libs/cli/src/server/web/agent-api.ts):
7	 *
8	 *   POST /api/sessions                      {projectId, agentSlug?, resumeSessionId?, budget?}
9	 *   POST /api/sessions/:id/message          {content}                         → 202
10	 *   GET  /api/sessions/:id/events?since=N&format=json                          → {events,lastSeq}
11	 *   GET  /api/sessions/:id/asks?format=json                                    → {asks}
12	 *   POST /api/sessions/:id/ask/:askId       {value}                            → answer a prompt
13	 *
14	 * The event stream is the full execution trace (sdk/org/libs/core/src/sandbox/trace.ts), so a
15	 * scenario can assert on the things that actually matter — which agents THING delegated to, which
16	 * consent-marked globals it called, which yields resolved, tokens burned, errors raised — instead
17	 * of grading a paragraph of prose.
18	 *
19	 * IMPORTANT (consent): the consent prompter is only wired for INTERACTIVE sessions
20	 * (session-manager.ts — `consentPrompter: args.interactive ? … : undefined`). A session created
21	 * through `POST /api/sessions` is interactive, so consent cards appear as asks here. Headless
22	 * paths (hooks, delegates, webhook dispatch) fail closed by design — that is a feature to assert,
23	 * not a bug to work around.
24	 */
25	
26	const sleep = (ms) => new Promise((r) => setTimeout(r, ms));
27	
28	export class ThingSession {
29	  /**
30	   * @param {import('./pod.mjs').Pod} pod
31	   * @param {object} opts
32	   * @param {string} [opts.projectId='user']   project to run in ('user' = the default project)
33	   * @param {string} [opts.agentSlug='thing']  THING is the default agent
34	   * @param {(descriptor:object)=>unknown} [opts.onAsk]  answer asks (consent cards, forms).
35	   *        Return `undefined` to leave the ask open (the scenario answers it manually).
36	   * @param {boolean} [opts.verbose=false]     stream a live log to stdout
37	   */
38	  constructor(pod, opts = {}) {
39	    this.pod = pod;
40	    this.projectId = opts.projectId ?? 'user';
41	    this.agentSlug = opts.agentSlug ?? 'thing';
42	    this.onAsk = opts.onAsk;
43	    this.verbose = opts.verbose ?? false;
44	    this.sessionId = null;
45	    /** every trace event seen, in order — the scenario's source of truth */
46	    this.events = [];
47	    /** asks the driver saw, with what it answered */
48	    this.asks = [];
49	    this.lastSeq = 0;
50	  }
51	
52	  log(...a) {
53	    if (this.verbose) console.log('[thing]', ...a);
54	  }
55	
56	  /** Create the session. Init is async pod-side — `send()` waits it out. */
57	  async start({ resumeSessionId, budget } = {}) {
58	    const body = {
59	      projectId: this.projectId,
60	      agentSlug: this.agentSlug,
61	      ...(resumeSessionId ? { resumeSessionId } : {}),
62	      ...(budget ? { budget } : {}),
63	    };
64	    const { sessionId } = await this.pod.req('POST', '/api/sessions', body);
65	    this.sessionId = sessionId;
66	    this.log('session', sessionId);
67	    return sessionId;
68	  }
69	
70	  /** Resume an existing session id (post-restart auto-resume scenario). */
71	  async resume(sessionId) {
72	    return this.start({ resumeSessionId: sessionId });
73	  }
74	
75	  /**
76	   * Fast-forward past a RESUMED session's existing trace without attributing it to the next turn.
77	   *
78	   * A scenario that runs Act-by-Act (`--acts=`) resumes the same session from a FRESH process, where
79	   * `lastSeq` starts at 0 — so the first `pullEvents()` replays the WHOLE session history and
80	   * `turn(startSeq)` folds it into the first turn's slice. Any assertion over that slice then reads
81	   * *earlier Acts'* displays: scenario 10 saw a restraint check "pass" on a build summary printed
82	   * two Acts ago. Call this right after `start()`/`resume()` so a turn's events are only its own.
83	   */
84	  async syncToTail() {
85	    for (let i = 0; i < 30; i++) {
86	      const before = this.lastSeq;
87	      await this.pullEvents();
88	      if (this.lastSeq === before) break;
89	      await sleep(200);
90	    }
91	    this.events.length = 0; // replayed history is not the next turn's work
92	    return this.lastSeq;
93	  }
94	
95	  /**
96	   * Pull new trace events since `lastSeq`.
97	   *
98	   * A long turn can spawn many delegate/headless sub-sessions; on a small pod (`maxSessions`) the
99	   * session manager may EVICT this top-level session shortly after its turn completes, so a poll
100	   * then 404s ("unknown session"). That is not a turn failure — the work already landed (assert it
101	   * on real pod state). So a 404 is surfaced as a soft signal (`this.sessionGone = true`) rather
102	   * than thrown; the settle loop treats it as turn-end once work has been seen.
103	   */
104	  async pullEvents() {
105	    let res;
106	    try {
107	      res = await this.pod.req('GET', `/api/sessions/${this.sessionId}/events?since=${this.lastSeq}&format=json`);
108	    } catch (err) {
109	      if (err?.status === 404) {
110	        this.sessionGone = true;
111	        return [];
112	      }
113	      throw err;
114	    }
115	    const { events, lastSeq } = res;
116	    for (const e of events ?? []) {
117	      this.events.push(e.event);
118	      if (this.verbose) this.#logEvent(e.event);
119	    }
120	    if (typeof lastSeq === 'number') this.lastSeq = lastSeq;
121	    return events ?? [];
122	  }
123	
124	  #logEvent(ev) {
125	    switch (ev.type) {
126	      case 'yield':
127	        this.log(`  yield ${ev.kind}`, JSON.stringify(ev.args)?.slice(0, 140));
128	        break;
129	      case 'display':
130	        this.log('  display', JSON.stringify(ev.descriptor)?.slice(0, 200));
131	        break;
132	      case 'node_start':
133	        this.log(`  node_start ${ev.kind} ${ev.label}`);
134	        break;
135	      case 'node_end':
136	        this.log(`  node_end ${ev.nodeId} ${ev.status} ${ev.durationMs}ms`);
137	        break;
138	      case 'eval_error':
139	      case 'typecheck_error':
140	        this.log(`  !! ${ev.type}: ${ev.message?.slice(0, 200)}`);
141	        break;
142	      default:
143	        break;
144	    }
145	  }
146	
147	  /** Open asks, with the raw descriptor (a ConsentCard is `descriptor.type === 'ConsentCard'`). */
148	  async openAsks() {
149	    const { asks } = await this.pod.req('GET', `/api/sessions/${this.sessionId}/asks?format=json`);
150	    return asks ?? [];
151	  }
152	
153	  /**
154	   * Answer an ask. Consent approval is anything in {true, 'approve', {approved:true},
155	   * {approve:true}} (core/src/globals/consent.ts `isConsentApproval`); ANYTHING else — including
156	   * null — is a denial.
157	   */
158	  async answerAsk(askId, value) {
159	    await this.pod.req('POST', `/api/sessions/${this.sessionId}/ask/${askId}`, { value });
160	    this.log('answered ask', askId, JSON.stringify(value));
161	  }
162	
163	  /**
164	   * Send a user message and wait for the turn to settle.
165	   *
166	   * "Settled" = the session is idle AND the trace has stopped growing for `quietMs`. We can't
167	   * key on a single `turn_end` because delegates/forks emit their own in sub-contexts; the
168	   * idle+quiet pair is the only reliable edge over HTTP.
169	   *
170	   * While waiting we drain asks through `onAsk` — that is how consent cards get approved mid-turn.
171	   * A turn blocked on an unanswered ask never goes idle, so an un-handled consent card surfaces as
172	   * a timeout with the ask still open (which the scenario can assert on).
173	   */
174	  /**
175	   * Ensure `this.sessionId` still exists; if it was evicted (`maxSessions` on a small pod), start a
176	   * fresh session — resuming the old id when the pod still has its snapshot, else a clean new one.
177	   * The project (its spaces, app, db) persists on disk regardless, so a re-established session still
178	   * sees everything built so far; only in-VM conversation memory is lost (acceptable — the scenario
179	   * drives self-contained follow-ups).
180	   */
181	  async #ensureAlive() {
182	    if (!this.sessionId) return;
183	    const list = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
184	    const alive = (list.sessions ?? []).some((s) => s.sessionId === this.sessionId);
185	    if (alive) return;
186	    this.log('session evicted — re-establishing');
187	    const prev = this.sessionId;
188	    try {
189	      await this.start({ resumeSessionId: prev });
190	    } catch {
191	      await this.start();
192	    }
193	    this.lastSeq = 0;
194	    this.sessionGone = false;
195	  }
196	
197	  async send(content, opts = {}) {
198	    await this.#ensureAlive();
199	    return this.#dispatchAndWait(
200	      () => this.pod.req('POST', `/api/sessions/${this.sessionId}/message`, { content }),
201	      content,
202	      opts,
203	    );
204	  }
205	
206	  /**
207	   * Send a user message WITH attachments (the file-upload path the real UI uses).
208	   *
209	   * The HTTP `POST /message` route is content-only — it silently drops attachments
210	   * (`sessions.ts` wires `sendMessage: (content) => manager.sendMessage(id, content)`, no third
211	   * arg). Only the WebSocket path carries `attachmentIds` (`ws/agent.ts` →
212	   * `msg.attachments.map(a => a.id)`). So to attach a file we open the same `/api/ws` socket the
213	   * `/chat` SPA uses, send one `{type:'sendMessage', content, attachments}` frame, then fall back to
214	   * the normal HTTP trace-poll to await the turn (the socket also streams the trace, but reusing the
215	   * HTTP settle-loop keeps one code path for "turn finished").
216	   *
217	   * @param {string} content
218	   * @param {Array<{id:string,kind:string,mediaType:string,url?:string,filename?:string}>} attachments
219	   *        AttachmentRefs from `pod.upload()`. The server trusts only `id` (re-reads bytes by id).
220	   */
221	  async sendWithAttachments(content, attachments, opts = {}) {
222	    const refs = attachments.map((a) => ({
223	      id: a.id,
224	      kind: a.kind,
225	      mediaType: a.mediaType,
226	      url: a.url ?? `/api/uploads/${a.id}`,
227	      ...(a.filename ? { filename: a.filename } : {}),
228	    }));
229	    await this.#ensureAlive();
230	    return this.#dispatchAndWait(
231	      () => this.#wsSend({ type: 'sendMessage', content, attachments: refs }),
232	      `${content}  [+${refs.length} attachment(s)]`,
233	      opts,
234	    );
235	  }
236	
237	  /** Open the pod's chat WebSocket, send one frame, resolve when it's flushed, then close. */
238	  #wsSend(frame) {
239	    const wsBase = this.pod.base.replace(/^http/, 'ws');
240	    const tokenQ = this.pod.token ? `&access_token=${encodeURIComponent(this.pod.token)}` : '';
241	    const url = `${wsBase}/api/ws?sessionId=${this.sessionId}${tokenQ}`;
242	    return new Promise((resolve, reject) => {
243	      const ws = new WebSocket(url); // Node ≥22 global WebSocket — zero-dep
244	      const fail = (e) => reject(e instanceof Error ? e : new Error(`ws error: ${JSON.stringify(e)}`));
245	      ws.addEventListener('open', () => {
246	        ws.send(JSON.stringify(frame));
247	        // Give the frame a beat to flush, then close; the turn is awaited over HTTP.
248	        setTimeout(() => {
249	          try {
250	            ws.close();
251	          } catch {
252	            /* ignore */
253	          }
254	          resolve();
255	        }, 750);
256	      });
257	      ws.addEventListener('error', fail);
258	    });
259	  }
260	
261	  async #dispatchAndWait(dispatch, logLine, { timeoutMs = 600_000, quietMs = 4_000, pollMs = 1_500 } = {}) {
262	    const startSeq = this.events.length;
263	    const t0 = Date.now();
264	    await dispatch();
265	    this.log('→', logLine.slice(0, 140));
266	
267	    let lastChange = Date.now();
268	    let sawWork = false;
269	    let quietSince = null;
270	    this.sessionGone = false;
271	
272	    while (Date.now() - t0 < timeoutMs) {
273	      const fresh = await this.pullEvents();
274	      if (fresh.length) {
275	        lastChange = Date.now();
276	        sawWork = true;
277	        quietSince = null;
278	      }
279	
280	      // If the session was evicted AFTER we saw the turn's work (a long turn's many sub-sessions
281	      // can push a small pod past `maxSessions`), the turn is effectively done — stop cleanly and
282	      // let the scenario assert on real pod state. If it vanished BEFORE any work, that's a real
283	      // failure (e.g. a mid-init pod restart), so surface it.
284	      if (this.sessionGone) {
285	        if (sawWork) return this.turn(startSeq, Date.now() - t0);
286	        throw new Error(`session ${this.sessionId} disappeared before doing any work (pod restart mid-init?)`);
287	      }
288	
289	      // Drain asks (consent cards, forms) — an unanswered ask stalls the turn forever.
290	      for (const ask of await this.openAsks().catch(() => [])) {
291	        if (this.asks.some((a) => a.id === ask.id)) continue;
292	        const answer = this.onAsk ? this.onAsk(ask.descriptor, ask) : undefined;
293	        this.asks.push({ id: ask.id, descriptor: ask.descriptor, answered: answer });
294	        if (answer !== undefined) {
295	          await this.answerAsk(ask.id, answer).catch(() => {});
296	          lastChange = Date.now();
297	        }
298	      }
299	
300	      const sessions = await this.pod.req('GET', '/api/sessions').catch(() => ({ sessions: [] }));
301	      const me = (sessions.sessions ?? []).find((s) => s.sessionId === this.sessionId);
302	      const idle = me?.status === 'idle';
303	      if (me?.status === 'error') {
304	        await this.pullEvents();
305	        throw new Error(`session entered error state: ${JSON.stringify(me)}`);
306	      }
307	      // Session no longer listed but we saw work → treat as completed (same eviction case).
308	      if (sawWork && !me && this.events.length > startSeq) {
309	        return this.turn(startSeq, Date.now() - t0);
310	      }
311	
312	      if (sawWork && idle && Date.now() - lastChange >= quietMs) {
313	        if (quietSince === null) quietSince = Date.now();
314	        await this.pullEvents(); // final drain
315	        return this.turn(startSeq, Date.now() - t0);
316	      }
317	      await sleep(pollMs);
318	    }
319	    await this.pullEvents();
320	    const open = await this.openAsks();
321	    throw Object.assign(
322	      new Error(
323	        `turn timed out after ${timeoutMs}ms` +
324	          (open.length ? ` with ${open.length} unanswered ask(s): ${JSON.stringify(open)}` : ''),
325	      ),
326	      { turn: this.turn(startSeq, Date.now() - t0), openAsks: open },
327	    );
328	  }
329	
330	  /** A view over just the events of one turn, with the derived facts a scenario asserts on. */
331	  turn(startSeq = 0, durationMs = 0) {
332	    const evs = this.events.slice(startSeq);
333	    return {
334	      durationMs,
335	      events: evs,
336	      text: textOf(evs),
337	      /** ONLY the turn's final display — the reply the user actually reads. `text` concatenates every
338	       *  display in the slice, which on a RESUMED session can still include replayed history, so a
339	       *  check about "what it answered" must read this, never `text`. */
340	      lastText: lastTextOf(evs),
341	      yields: evs.filter((e) => e.type === 'yield').map((e) => ({ kind: e.kind, args: e.args })),
342	      delegates: evs
343	        .filter((e) => e.type === 'yield' && e.kind === 'delegate')
344	        .map((e) => delegateRef(e.args)),
345	      errors: evs
346	        .filter((e) => e.type === 'eval_error' || e.type === 'typecheck_error')
347	        .map((e) => ({ type: e.type, message: e.message, statement: e.statement })),
348	      tokens: evs.reduce(
349	        (acc, e) =>
350	          e.type === 'llm_response'
351	            ? { in: acc.in + (e.inputTokens ?? 0), out: acc.out + (e.outputTokens ?? 0) }
352	            : acc,
353	        { in: 0, out: 0 },
354	      ),
355	      llmCalls: evs.filter((e) => e.type === 'llm_response').length,
356	      nodes: evs
357	        .filter((e) => e.type === 'node_end')
358	        .map((e) => ({ id: e.nodeId, status: e.status, ms: e.durationMs, error: e.error })),
359	    };
360	  }
361	
362	  /** Did the agent call this yield kind anywhere in the session? (e.g. 'installSpace') */
363	  didYield = (kind) => this.events.some((e) => e.type === 'yield' && e.kind === kind);
364	  /** Did it delegate to this `space/agent` (or just this space)? */
365	  didDelegate = (ref) =>
366	    this.events.some(
367	      (e) => e.type === 'yield' && e.kind === 'delegate' && delegateRef(e.args).startsWith(ref),
368	    );
369	  /** All consent cards raised this session. */
370	  consentCards = () => this.asks.filter((a) => a.descriptor?.type === 'ConsentCard');
371	
372	  /** Full session totals — for the performance table in the scenario report. */
373	  stats() {
374	    const t = this.turn(0, 0);
375	    return {
376	      events: this.events.length,
377	      llmCalls: t.llmCalls,
378	      tokens: t.tokens,
379	      errors: t.errors.length,
380	      delegates: t.delegates,
381	      yieldKinds: [...new Set(t.yields.map((y) => y.kind))],
382	    };
383	  }
384	}
385	
386	/** Human-readable delegate target from the yield args (`{space, agent, action}` or positional). */
387	function delegateRef(args) {
388	  if (Array.isArray(args)) return args.slice(0, 3).filter(Boolean).join('/');
389	  if (args && typeof args === 'object') {
390	    const { space, agent, action } = args;
391	    return [space, agent, action].filter(Boolean).join('/');
392	  }
393	  return String(args);
394	}
395	
396	/** The prose THING showed the user: display() descriptors + the final assistant text. */
397	export function textOf(events) {
398	  const out = [];
399	  for (const e of events) {
400	    if (e.type === 'display') {
401	      const d = e.descriptor;
402	      const s =
403	        typeof d === 'string'
404	          ? d
405	          : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
406	      out.push(typeof s === 'string' ? s : JSON.stringify(s));
407	    }
408	  }
409	  return out.join('\n');
410	}
411	
412	/** The LAST thing THING displayed — its final reply for this turn (see `turn().lastText`). */
413	export function lastTextOf(events) {
414	  for (let i = events.length - 1; i >= 0; i--) {
415	    const e = events[i];
416	    if (e.type !== 'display') continue;
417	    const d = e.descriptor;
418	    const s =
419	      typeof d === 'string'
420	        ? d
421	        : (d?.props?.text ?? d?.props?.children ?? d?.props?.content ?? JSON.stringify(d));
422	    const out = typeof s === 'string' ? s : JSON.stringify(s);
423	    if (out && out.trim()) return out;
424	  }
425	  return '';
426	}
427	
428	/** Approve every consent card; leave other asks for the scenario. */
429	export const approveAllConsent = (descriptor) =>
430	  descriptor?.type === 'ConsentCard' ? true : undefined;
431	/** Deny every consent card (for the denial branch of the consent scenario). */
432	export const denyAllConsent = (descriptor) =>
433	  descriptor?.type === 'ConsentCard' ? false : undefined;
434

