    /insur/.test(blob) && [/propert|mortgage/, /pension|saving/, /subscrip/, /account/].filter((rx) => rx.test(blob)).length >= 2,
    spaces.join(', '));

  // App — nudge the build if the automator half didn't fire.
  let names = await tableNames(pod, PROJECT);
