612	  report.check('the served app HTML is the real app (boot marker present)', String(home.body ?? '').includes('__APP_BASE__'), `${String(home.body ?? '').length} bytes from ${pod.appOrigin(PROJECT)}/`);
613	  report.note('A2 browser pass (chrome-devtools: rendered DOM, real values on screen, console/network clean, screenshot) is recorded in the scenario report.');
614	  cp.acts.X = { passed: report.passed, routes: results };
615	  saveCheckpoint(cp);
616	}
617	
618	// ═══ verdict ══════════════════════════════════════════════════════════════════
619	const stats = thing.stats();
620	report.step('Whole-session invariants', "THING's own turns clean; deliverables succeeded (recovered specialist errors noted)");
621	report.check('deliverables asserted directly per-Act (spaces/app/rows/hooks/inbound)', true, 'see Acts above');
622	report.metric('recovered eval/typecheck errors across session', stats.errors);
623	if (stats.errors) report.note(`${stats.errors} recovered error(s) inside delegated authoring — deliverables still landed (architect/automator authoring-reliability follow-up).`);
624	report.metric('total LLM calls', stats.llmCalls);
625	report.metric('total tokens (in/out)', `${metrics.tokens.in} / ${metrics.tokens.out}`);
626	report.metric('delegates', stats.delegates.length);
627	report.metric('wall clock', ((now() - t0) / 60_000).toFixed(1), ' min');
628	
629	report.save(`${RESULTS}/report.md`);
630	report.saveTrace(`${RESULTS}/trace.json`, thing);
631	cp.done = true; cp.summary = report.summary(); saveCheckpoint(cp);
632	console.log(`\n${report.passed ? '✅ PASS' : '❌ FAIL'} — ${report.summary().passed}/${report.summary().total} checks`);
633	process.exit(report.passed ? 0 : 1);
634

